    mode: DragMode;
    actionId: string;
    startMouseX: number;
    startMouseY: number;
    scaleX: number;
    scaleY: number;
    startBounds: OverlayBounds;
    startFullBounds: OverlayBounds;
    startCropValues: CropValues;
