        MIN_CLIP_SIZE / Math.max(MIN_CLIP_SIZE, state.startFullBounds.width),
      );
      const minVisibleHeightFraction = Math.min(
        MAX_CROP_FRACTION,
        MIN_CLIP_SIZE / Math.max(MIN_CLIP_SIZE, state.startFullBounds.height),
      );
